# --- Input Validation ---
def sanitize_string(value, max_length=200):
    """Sanitize and validate string input."""
    if value is None:
        return None
    if not isinstance(value, str):
        raise ValueError("Expected string input")
    # Truncate to max length
    value = value[:max_length]
    # Remove control characters but allow normal whitespace
    value = re.sub(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]', '', value)
    return value.strip()


def validate_id(value):
    """Validate that an ID is alphanumeric."""
    if value is None:
        return None
    value = str(value).strip()
    if not re.match(r'^[a-zA-Z0-9_-]+$', value):
        raise ValueError("Invalid ID format")
    if len(value) > 50:
        raise ValueError("ID too long")
    return value


def validate_positive_int(value, max_val=1000):
    """Validate positive integer within bounds."""
    if value is None:
        return None
    try:
        val = int(value)
    except (TypeError, ValueError):
        raise ValueError("Expected integer input")
    if val < 0:
        raise ValueError("Value must be non-negative")
    if val > max_val:
        return max_val
    return val


def validate_rating(value):
    """Validate rating is between 1 and 5."""
    if value is None:
        return None
    val = validate_positive_int(value, max_val=5)
    if val < 1:
        raise ValueError("Rating must be between 1 and 5")
    return val


# --- Query Depth Analysis ---
def calculate_query_depth(query_string):
    """Estimate query depth by counting nested braces."""
    depth = 0
    max_depth = 0
    for char in query_string:
        if char == '{':
            depth += 1
            max_depth = max(max_depth, depth)
        elif char == '}':
            depth -= 1
    return max_depth


def estimate_query_complexity(query_string):
    """Estimate query complexity based on field count."""
    # Count field-like tokens (simple heuristic)
    fields = re.findall(r'[a-zA-Z_]\w*(?=\s*[\({:]|\s*\n|\s*})', query_string)
    return len(fields)


def check_for_introspection(query_string):
    """Check if query contains introspection when disabled."""
    introspection_patterns = ['__schema', '__type', '__typename']
    query_lower = query_string.lower()
    # Allow __typename as it's commonly needed, block __schema and __type
    for pattern in ['__schema', '__type']:
        if pattern in query_lower:
            return True
    return False


