# --- Authentication Middleware ---
def verify_api_token(token):
    """Verify API token using constant-time comparison against stored hash."""
    if not token or not Config.API_TOKEN_HASH:
        return False
    token_hash = hashlib.sha256(token.encode('utf-8')).hexdigest()
    return secrets.compare_digest(token_hash, Config.API_TOKEN_HASH)


def require_auth(f):
    """Decorator to require authentication for endpoints."""
    @wraps(f)
    def decorated(*args, **kwargs):
        # In development with no token configured, allow access with a warning
        if Config.ENVIRONMENT == 'development' and not Config.API_TOKEN_HASH:
            logger.warning("API running without authentication - development mode only")
            return f(*args, **kwargs)

        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({"errors": [{"message": "Authentication required"}]}), 401

        token = auth_header[7:]  # Strip 'Bearer '
        if not verify_api_token(token):
            logger.warning("Failed authentication attempt from %s", request.remote_addr)
            return jsonify({"errors": [{"message": "Invalid authentication token"}]}), 401

        return f(*args, **kwargs)
    return decorated


