@app.before_request
def before_request_checks():
    """Apply security checks before processing any request."""
    # Rate limiting
    client_ip = request.remote_addr
    if rate_limiter.is_rate_limited(client_ip, Config.RATE_LIMIT_REQUESTS, Config.RATE_LIMIT_WINDOW):
        logger.warning("Rate limit exceeded for %s", client_ip)
        return jsonify({"errors": [{"message": "Rate limit exceeded. Please try again later."}]}), 429


@app.after_request
def set_security_headers(response):
    """Set security headers on all responses."""
    response.headers['Content-Type'] = 'application/json'
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    # Remove server header
    response.headers.pop('Server', None)
    return response


@app.route('/graphql', methods=['POST'])
@require_auth
def graphql_endpoint():
    """Main GraphQL endpoint with security validations."""
    # Validate content type
    content_type = request.content_type or ''
    if 'application/json' not in content_type:
        return jsonify({"errors": [{"message": "Content-Type must be application/json"}]}), 415

    # Parse request body
    try:
        data = request.get_json(force=False, silent=False)
    except Exception:
        return jsonify({"errors": [{"message": "Invalid JSON body"}]}), 400

    if not data or not isinstance(data, dict):
        return jsonify({"errors": [{"message": "Request body must be a JSON object"}]}), 400

    query = data.get('query', '')
    variables = data.get('variables')
    operation_name = data.get('operationName')

    # Validate query is a string
    if not isinstance(query, str):
        return jsonify({"errors": [{"message": "Query must be a string"}]}), 400

    # Validate query length
    if len(query) > Config.MAX_QUERY_LENGTH:
        logger.warning("Query length exceeded from %s: %d chars", request.remote_addr, len(query))
        return jsonify({"errors": [{"message": "Query too long"}]}), 400

    # Validate variables if present
    if variables is not None and not isinstance(variables, dict):
        return jsonify({"errors": [{"message": "Variables must be a JSON object"}]}), 400

    # Validate operation name if present
    if operation_name is not None:
        if not isinstance(operation_name, str) or not re.match(r'^[a-zA-Z_]\w{0,100}$', operation_name):
            return jsonify({"errors": [{"message": "Invalid operation name"}]}), 400

    # Check introspection
    if not Config.INTROSPECTION_ENABLED and check_for_introspection(query):
        logger.info("Introspection query blocked from %s", request.remote_addr)
        return jsonify({"errors": [{"message": "Introspection is disabled"}]}), 400

    # Check query depth
    depth = calculate_query_depth(query)
    if depth > Config.MAX_QUERY_DEPTH:
        logger.warning("Query depth exceeded from %s: depth=%d", request.remote_addr, depth)
        return jsonify({"errors": [{"message": "Query depth exceeds maximum allowed"}]}), 400

    # Check query complexity
    complexity = estimate_query_complexity(query)
    if complexity > Config.MAX_QUERY_COMPLEXITY:
        logger.warning("Query complexity exceeded from %s: complexity=%d", request.remote_addr, complexity)
        return jsonify({"errors": [{"message": "Query complexity exceeds maximum allowed"}]}), 400

    # Block mutation/subscription attempts (read-only API)
    query_stripped = query.strip()
    if query_stripped.startswith('mutation') or query_stripped.startswith('subscription'):
        return jsonify({"errors": [{"message": "Only queries are supported"}]}), 400

    # Execute query
    try:
        result = schema.execute(
            query,
            variables=variables,
            operation_name=operation_name,
        )
    except Exception as e:
        logger.error("GraphQL execution error: %s", type(e).__name__)
        return jsonify({"errors": [{"message": "Internal server error"}]}), 500

    response_data = {}

    if result.data:
        response_data["data"] = result.data

    if result.errors:
        # Sanitize error messages - don't expose internal details
        sanitized_errors = []
        for error in result.errors:
            error_msg = str(error)
            # In production, use generic messages
            if Config.ENVIRONMENT == 'production':
                sanitized_errors.append({"message": "An error occurred processing your request"})
                logger.error("GraphQL error (hidden from client): %s", error_msg)
            else:
                # In development, show errors but still sanitize
                sanitized_errors.append({
                    "message": error_msg[:500],  # Truncate long error messages
                    "locations": [{"line": loc.line, "column": loc.column} for loc in (error.locations or [])]
                })
        response_data["errors"] = sanitized_errors

    if not response_data:
        response_data = {"data": None}

    return jsonify(response_data), 200


